// ─── SUPABASE CONFIG ──────────────────────────────────────────────────────────
const SB_URL = "https://arrendpmuwdhrfwvokhv.supabase.co";
const SB_KEY = "sb_publishable_e5hLLlXWBVV8NkNUAz3Blg_8oMwP3Wt";

const sb = {
  headers: {
    "apikey":        SB_KEY,
    "Authorization": `Bearer ${SB_KEY}`,
    "Content-Type":  "application/json",
    "Prefer":        "return=representation",
  },
  async select(table, filters="") {
    const res = await fetch(`${SB_URL}/rest/v1/${table}?${filters}&order=created_at.asc`, { headers: sb.headers });
    if (!res.ok) throw new Error(await res.text());
    return res.json();
  },
  async insert(table, row) {
    const res = await fetch(`${SB_URL}/rest/v1/${table}`, {
      method:"POST", headers:sb.headers, body:JSON.stringify(row),
    });
    if (!res.ok) throw new Error(await res.text());
    const d = await res.json(); return Array.isArray(d)?d[0]:d;
  },
  async upsert(table, row, onConflict) {
    const url = onConflict ? `${SB_URL}/rest/v1/${table}?on_conflict=${onConflict}` : `${SB_URL}/rest/v1/${table}`;
    const res = await fetch(url, {
      method:"POST",
      headers:{...sb.headers,"Prefer":"resolution=merge-duplicates,return=representation"},
      body:JSON.stringify(row),
    });
    if (!res.ok) throw new Error(await res.text());
    const d = await res.json(); return Array.isArray(d)?d[0]:d;
  },
  async delete(table, id) {
    const res = await fetch(`${SB_URL}/rest/v1/${table}?id=eq.${id}`, {
      method:"DELETE", headers:sb.headers,
    });
    if (!res.ok) throw new Error(await res.text());
  },
  async deleteById(table, id) {
    const res = await fetch(`${SB_URL}/rest/v1/${table}?id=eq.${encodeURIComponent(id)}`, {
      method:"DELETE", headers:sb.headers,
    });
    if (!res.ok) throw new Error(await res.text());
  },
};

